import { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import API from '../services/axios';

const CATEGORIES = ['All', 'Concert', 'Conference', 'Workshop', 'Sports', 'Exhibition', 'Festival', 'Comedy', 'Theatre', 'Other'];

// Beautiful fallback images per category
const CATEGORY_IMAGES = {
  Concert: 'https://images.unsplash.com/photo-1501386761578-eac5c94b800a?w=600&q=80',
  Festival: 'https://images.unsplash.com/photo-1533174072545-7a4b6ad7a6c3?w=600&q=80',
  Sports: 'https://images.unsplash.com/photo-1471295253337-3ceaaedca402?w=600&q=80',
  Workshop: 'https://images.unsplash.com/photo-1552664730-d307ca884978?w=600&q=80',
  Conference: 'https://images.unsplash.com/photo-1540575467063-178a50c2df87?w=600&q=80',
  Exhibition: 'https://images.unsplash.com/photo-1513364776144-60967b0f800f?w=600&q=80',
  Comedy: 'https://images.unsplash.com/photo-1527224538127-2104bb71c51b?w=600&q=80',
  Theatre: 'https://images.unsplash.com/photo-1507676184212-d03ab07a01bf?w=600&q=80',
  Other: 'https://images.unsplash.com/photo-1492684223066-81342ee5ff30?w=600&q=80',
  default: 'https://images.unsplash.com/photo-1470229722913-7c0e2dbbafd3?w=600&q=80',
};

// Demo events shown when DB is empty
const DEMO_EVENTS = [
  {
    _id: 'demo1', name: 'Neon Night Party', category: 'Festival', price: 799,
    venue: 'Sky Lounge, Mumbai', date: '2026-04-15', time: '20:00',
    availableSeats: 120, totalSeats: 200, status: 'upcoming',
    image: 'https://images.unsplash.com/photo-1516450360452-9312f5e86fc7?w=600&q=80'
  },
  {
    _id: 'demo2', name: 'Summer Music Festival', category: 'Concert', price: 1299,
    venue: 'Beach Arena, Goa', date: '2026-05-20', time: '18:00',
    availableSeats: 500, totalSeats: 1000, status: 'upcoming',
    image: 'https://images.unsplash.com/photo-1501386761578-eac5c94b800a?w=600&q=80'
  },
  {
    _id: 'demo3', name: 'Rooftop DJ Night', category: 'Concert', price: 599,
    venue: 'The Terrace, Bangalore', date: '2026-04-28', time: '21:00',
    availableSeats: 80, totalSeats: 150, status: 'upcoming',
    image: 'https://images.unsplash.com/photo-1571266028243-d220c6a9e7b6?w=600&q=80'
  },
  {
    _id: 'demo4', name: 'Startup Conference 2026', category: 'Conference', price: 2499,
    venue: 'Convention Centre, Delhi', date: '2026-06-10', time: '09:00',
    availableSeats: 300, totalSeats: 500, status: 'upcoming',
    image: 'https://images.unsplash.com/photo-1540575467063-178a50c2df87?w=600&q=80'
  },
  {
    _id: 'demo5', name: 'Holi Colour Fest', category: 'Festival', price: 399,
    venue: 'Central Park, Hyderabad', date: '2026-03-25', time: '10:00',
    availableSeats: 0, totalSeats: 400, status: 'upcoming',
    image: 'https://images.unsplash.com/photo-1615961244836-b6dd9a86eb42?w=600&q=80'
  },
  {
    _id: 'demo6', name: 'Stand-Up Comedy Night', category: 'Comedy', price: 699,
    venue: 'Laugh Factory, Chennai', date: '2026-04-05', time: '19:30',
    availableSeats: 60, totalSeats: 100, status: 'upcoming',
    image: 'https://images.unsplash.com/photo-1527224538127-2104bb71c51b?w=600&q=80'
  },
  {
    _id: 'demo7', name: 'Art & Culture Exhibition', category: 'Exhibition', price: 299,
    venue: 'National Gallery, Kolkata', date: '2026-05-01', time: '11:00',
    availableSeats: 200, totalSeats: 300, status: 'upcoming',
    image: 'https://images.unsplash.com/photo-1513364776144-60967b0f800f?w=600&q=80'
  },
  {
    _id: 'demo8', name: 'IPL Watch Party', category: 'Sports', price: 499,
    venue: 'Sports Bar, Pune', date: '2026-04-18', time: '19:00',
    availableSeats: 150, totalSeats: 200, status: 'upcoming',
    image: 'https://images.unsplash.com/photo-1531415074968-036ba1b575da?w=600&q=80'
  },
];

function Home() {
  const [events, setEvents] = useState([]);
  const [filtered, setFiltered] = useState([]);
  const [search, setSearch] = useState('');
  const [locationFilter, setLocationFilter] = useState('');
  const [category, setCategory] = useState('All');
  const [loading, setLoading] = useState(true);

  useEffect(() => { fetchEvents(); }, []);

  useEffect(() => {
    let result = events;
    if (search) result = result.filter(e => e.name.toLowerCase().includes(search.toLowerCase()));
    if (locationFilter) result = result.filter(e => e.venue.toLowerCase().includes(locationFilter.toLowerCase()));
    if (category !== 'All') result = result.filter(e => e.category === category);
    setFiltered(result);
  }, [search, locationFilter, category, events]);

  const fetchEvents = async () => {
    try {
      const res = await API.get('/events');
      const data = res.data.events || [];
      // Use demo events if DB is empty
      const finalEvents = data.length > 0 ? data : DEMO_EVENTS;
      setEvents(finalEvents);
      setFiltered(finalEvents);
    } catch {
      setEvents(DEMO_EVENTS);
      setFiltered(DEMO_EVENTS);
    } finally {
      setLoading(false);
    }
  };

  const getImage = (event) =>
    event.image || CATEGORY_IMAGES[event.category] || CATEGORY_IMAGES.default;

  return (
    <div style={{ minHeight: '100vh' }}>

      {/* HERO */}
      <section style={{
        background: 'linear-gradient(135deg, #1e1b4b 0%, #312e81 40%, #4c1d95 100%)',
        padding: '5rem 2rem 4rem', position: 'relative', overflow: 'hidden'
      }}>
        <div style={{ position: 'absolute', top: '-100px', right: '-100px', width: '500px', height: '500px', borderRadius: '50%', background: 'radial-gradient(circle, rgba(167,139,250,0.15) 0%, transparent 70%)', pointerEvents: 'none' }} />
        <div style={{ position: 'absolute', bottom: '-50px', left: '-50px', width: '300px', height: '300px', borderRadius: '50%', background: 'radial-gradient(circle, rgba(124,58,237,0.2) 0%, transparent 70%)', pointerEvents: 'none' }} />

        <div style={{ maxWidth: '900px', margin: '0 auto', textAlign: 'center', position: 'relative' }}>
          <p style={{ color: '#a78bfa', fontSize: '0.85rem', fontWeight: '600', letterSpacing: '3px', marginBottom: '1rem', textTransform: 'uppercase' }}>
            Find Your Next Experience
          </p>
          <h1 style={{ fontSize: 'clamp(2.5rem, 5vw, 4rem)', fontWeight: '800', color: 'white', lineHeight: '1.15', marginBottom: '2rem' }}>
            Discover & Promote<br />
            <span style={{ color: '#a78bfa' }}>Upcoming Event</span>
          </h1>

          {/* Search Bar */}
          <div style={{
            background: 'rgba(255,255,255,0.08)', backdropFilter: 'blur(20px)',
            border: '1px solid rgba(255,255,255,0.15)', borderRadius: '16px',
            padding: '1rem 1.5rem', display: 'flex', gap: '1rem', alignItems: 'center',
            maxWidth: '750px', margin: '0 auto', flexWrap: 'wrap'
          }}>
            <div style={{ flex: 1, minWidth: '130px', display: 'flex', alignItems: 'center', gap: '8px' }}>
              <span style={{ color: '#a78bfa' }}>🔍</span>
              <input type="text" placeholder="Search Event..." value={search}
                onChange={(e) => setSearch(e.target.value)}
                style={{ background: 'transparent', border: 'none', outline: 'none', color: 'white', fontSize: '0.9rem', width: '100%' }} />
            </div>
            <div style={{ width: '1px', height: '28px', background: 'rgba(255,255,255,0.2)' }} />
            <div style={{ flex: 1, minWidth: '130px', display: 'flex', alignItems: 'center', gap: '8px' }}>
              <span style={{ color: '#a78bfa' }}>📍</span>
              <input type="text" placeholder="Search Location..." value={locationFilter}
                onChange={(e) => setLocationFilter(e.target.value)}
                style={{ background: 'transparent', border: 'none', outline: 'none', color: 'white', fontSize: '0.9rem', width: '100%' }} />
            </div>
            <div style={{ width: '1px', height: '28px', background: 'rgba(255,255,255,0.2)' }} />
            <select value={category} onChange={(e) => setCategory(e.target.value)}
              style={{ background: 'transparent', border: 'none', outline: 'none', color: 'white', fontSize: '0.85rem', cursor: 'pointer' }}>
              {CATEGORIES.map(c => <option key={c} value={c} style={{ background: '#312e81' }}>{c}</option>)}
            </select>
            <div style={{ width: '1px', height: '28px', background: 'rgba(255,255,255,0.2)' }} />
            <button style={{
              background: 'linear-gradient(135deg, #7c3aed, #a78bfa)', color: 'white',
              border: 'none', padding: '10px 24px', borderRadius: '10px',
              cursor: 'pointer', fontWeight: '600', fontSize: '0.85rem', whiteSpace: 'nowrap'
            }}>🔎 Search</button>
          </div>
        </div>
      </section>

      {/* CATEGORY PILLS */}
      <section style={{ background: 'rgba(30,27,75,0.95)', padding: '1rem 2rem', borderBottom: '1px solid rgba(255,255,255,0.08)' }}>
        <div style={{ maxWidth: '1400px', margin: '0 auto', display: 'flex', gap: '10px', overflowX: 'auto', paddingBottom: '4px' }}>
          {CATEGORIES.map(cat => (
            <button key={cat} onClick={() => setCategory(cat)} style={{
              padding: '8px 20px', borderRadius: '20px', border: 'none',
              cursor: 'pointer', fontWeight: '600', fontSize: '0.8rem', whiteSpace: 'nowrap',
              transition: 'all 0.2s',
              background: category === cat ? 'linear-gradient(135deg, #7c3aed, #a78bfa)' : 'rgba(255,255,255,0.08)',
              color: category === cat ? 'white' : 'rgba(255,255,255,0.6)',
              boxShadow: category === cat ? '0 4px 15px rgba(124,58,237,0.4)' : 'none'
            }}>{cat}</button>
          ))}
        </div>
      </section>

      {/* EVENTS GRID */}
      <section style={{
        background: 'linear-gradient(180deg, #1e1b4b 0%, #0f0c29 100%)',
        padding: '3rem 2rem', minHeight: '60vh'
      }}>
        <div style={{ maxWidth: '1400px', margin: '0 auto' }}>
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '2rem' }}>
            <h2 style={{ color: 'white', fontSize: '1.6rem', fontWeight: '800' }}>
              Upcoming Events
              <span style={{ color: '#a78bfa', fontSize: '1rem', fontWeight: '400', marginLeft: '10px' }}>({filtered.length})</span>
            </h2>
          </div>

          {loading ? (
            <div style={{ textAlign: 'center', padding: '4rem' }}>
              <div style={{ fontSize: '3rem', marginBottom: '1rem' }}>🎉</div>
              <p style={{ color: 'rgba(255,255,255,0.5)' }}>Loading events...</p>
            </div>
          ) : filtered.length === 0 ? (
            <div style={{ textAlign: 'center', padding: '4rem' }}>
              <div style={{ fontSize: '3rem', marginBottom: '1rem' }}>😕</div>
              <p style={{ color: 'rgba(255,255,255,0.5)' }}>No events found. Try a different search.</p>
            </div>
          ) : (
            <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(290px, 1fr))', gap: '1.5rem' }}>
              {filtered.map(event => (
                <div key={event._id} style={{
                  background: 'rgba(255,255,255,0.06)', backdropFilter: 'blur(20px)',
                  border: '1px solid rgba(255,255,255,0.1)', borderRadius: '18px',
                  overflow: 'hidden', transition: 'all 0.3s', cursor: 'pointer'
                }}
                  onMouseEnter={e => { e.currentTarget.style.transform = 'translateY(-6px)'; e.currentTarget.style.boxShadow = '0 20px 50px rgba(124,58,237,0.35)'; e.currentTarget.style.borderColor = 'rgba(167,139,250,0.4)'; }}
                  onMouseLeave={e => { e.currentTarget.style.transform = 'translateY(0)'; e.currentTarget.style.boxShadow = 'none'; e.currentTarget.style.borderColor = 'rgba(255,255,255,0.1)'; }}
                >
                  {/* Image */}
                  <div style={{ position: 'relative', height: '190px', overflow: 'hidden' }}>
                    <img src={getImage(event)} alt={event.name}
                      style={{ width: '100%', height: '100%', objectFit: 'cover', transition: 'transform 0.4s' }}
                      onMouseEnter={e => e.target.style.transform = 'scale(1.08)'}
                      onMouseLeave={e => e.target.style.transform = 'scale(1)'}
                      onError={e => { e.target.src = CATEGORY_IMAGES.default; }}
                    />
                    {/* Gradient overlay */}
                    <div style={{ position: 'absolute', inset: 0, background: 'linear-gradient(to top, rgba(15,12,41,0.8) 0%, transparent 60%)' }} />
                    {/* Category badge */}
                    <span style={{
                      position: 'absolute', top: '12px', left: '12px',
                      background: 'linear-gradient(135deg, #7c3aed, #a78bfa)',
                      color: 'white', padding: '4px 12px', borderRadius: '20px',
                      fontSize: '0.68rem', fontWeight: '700', letterSpacing: '0.5px'
                    }}>{event.category}</span>
                    {/* Sold out badge */}
                    {event.availableSeats === 0 && (
                      <span style={{
                        position: 'absolute', top: '12px', right: '12px',
                        background: 'rgba(239,68,68,0.9)', backdropFilter: 'blur(10px)',
                        color: 'white', padding: '4px 12px', borderRadius: '20px',
                        fontSize: '0.68rem', fontWeight: '700'
                      }}>SOLD OUT</span>
                    )}
                    {/* Price on image */}
                    <span style={{
                      position: 'absolute', bottom: '12px', right: '12px',
                      background: 'rgba(0,0,0,0.7)', backdropFilter: 'blur(10px)',
                      color: '#a78bfa', padding: '5px 12px', borderRadius: '20px',
                      fontSize: '0.85rem', fontWeight: '800'
                    }}>₹{event.price}</span>
                  </div>

                  {/* Content */}
                  <div style={{ padding: '1.2rem' }}>
                    <h3 style={{ color: 'white', fontWeight: '700', fontSize: '1rem', marginBottom: '0.6rem', lineHeight: '1.3' }}>{event.name}</h3>

                    <div style={{ display: 'flex', flexDirection: 'column', gap: '4px', marginBottom: '1rem' }}>
                      <p style={{ color: 'rgba(255,255,255,0.5)', fontSize: '0.78rem', display: 'flex', alignItems: 'center', gap: '6px' }}>
                        <span>📅</span>
                        {new Date(event.date).toLocaleDateString('en-IN', { day: 'numeric', month: 'short', year: 'numeric' })} • {event.time}
                      </p>
                      <p style={{ color: 'rgba(255,255,255,0.5)', fontSize: '0.78rem', display: 'flex', alignItems: 'center', gap: '6px' }}>
                        <span>📍</span>{event.venue}
                      </p>
                    </div>

                    {/* Seats progress */}
                    <div style={{ marginBottom: '1rem' }}>
                      <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '5px' }}>
                        <span style={{ color: 'rgba(255,255,255,0.4)', fontSize: '0.7rem' }}>Seats Available</span>
                        <span style={{ color: 'rgba(255,255,255,0.6)', fontSize: '0.7rem', fontWeight: '600' }}>{event.availableSeats}/{event.totalSeats}</span>
                      </div>
                      <div style={{ background: 'rgba(255,255,255,0.1)', borderRadius: '10px', height: '5px', overflow: 'hidden' }}>
                        <div style={{
                          height: '100%', borderRadius: '10px',
                          width: `${event.totalSeats > 0 ? (event.availableSeats / event.totalSeats) * 100 : 0}%`,
                          background: event.availableSeats === 0 ? '#ef4444' : event.availableSeats / event.totalSeats < 0.2 ? '#f59e0b' : 'linear-gradient(90deg, #7c3aed, #a78bfa)',
                          transition: 'width 0.5s ease'
                        }} />
                      </div>
                    </div>

                    <Link to={event._id.startsWith('demo') ? '/register' : `/events/${event._id}`} style={{
                      display: 'block', textAlign: 'center',
                      background: event.availableSeats === 0
                        ? 'rgba(255,255,255,0.08)'
                        : 'linear-gradient(135deg, #7c3aed, #a78bfa)',
                      color: event.availableSeats === 0 ? 'rgba(255,255,255,0.3)' : 'white',
                      padding: '11px', borderRadius: '12px', textDecoration: 'none',
                      fontWeight: '600', fontSize: '0.85rem', letterSpacing: '0.3px',
                      pointerEvents: event.availableSeats === 0 ? 'none' : 'auto',
                      transition: 'opacity 0.2s'
                    }}>
                      {event.availableSeats === 0 ? 'Sold Out' : 'Book Now 🎟️'}
                    </Link>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
      </section>

      {/* CTA */}
      <section style={{
        background: 'linear-gradient(135deg, #4c1d95, #7c3aed)',
        padding: '5rem 2rem', textAlign: 'center'
      }}>
        <div style={{ maxWidth: '600px', margin: '0 auto' }}>
          <h2 style={{ color: 'white', fontSize: '2.2rem', fontWeight: '800', marginBottom: '1rem' }}>
            Ready to Start Your Journey?
          </h2>
          <p style={{ color: 'rgba(255,255,255,0.7)', marginBottom: '2rem', fontSize: '1rem' }}>
            Join thousands of event-goers today!
          </p>
          <Link to="/register" style={{
            background: 'white', color: '#7c3aed', padding: '14px 40px',
            borderRadius: '30px', textDecoration: 'none', fontWeight: '800',
            fontSize: '1rem', display: 'inline-block', transition: 'transform 0.2s'
          }}>Sign Up Free 🚀</Link>
        </div>
      </section>
    </div>
  );
}
export default Home;
